    $children = $this->db->selectFieldValues(
        'categorylinks', 'cl_from',
        ['cl_to' => $catId, 'cl_type' => 'subcat']
    );
    $result = $children;
    foreach ($children as $child) {
        $result = array_merge(
            $result, $this->getDescendants($child, $depth + 1)
